  ('promotion-d1056197-moex-00123', 'promotion-d1056197', 'promotion-d1056197-moex-110-d3ff7f6b', 'sub-promotion-d1056197-01', NULL, 'single_choice', '假設經濟體系中有兩位消費者（A和B），兩種財貨（X和Y）。消費者A的初始稟賦為（X=15, Y = 5）而消費者B的初始稟賦為（X = 5, Y= 15 ）。消費者A和B的效用函數皆為 U(X,Y) = XY。當市場目前的相對價格（P /P ）為$2時，下列敘述何者正確？ X Y', '["X財貨的市場有超額需求", "Y財貨的市場有超額需求", "X財貨的市場達到均衡", "Y財貨的市場達到均衡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:14+00:00", "source_pdf_sha1": "7daa79136592", "answer_pdf_sha1": "1241ad1f8015", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "135", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "僑務行政"}'::jsonb, NULL),
